2480→export function analyzeFormComplexity(ariaSnapshot: string, url: string): FormComplexityAnalysis {
2481→  const lines = ariaSnapshot.split("\n");
2482→
2483→  // Count form fields
2484→  const fieldPatterns = /role="(textbox|combobox|listbox|radio|checkbox|spinbutton)"|type="(text|email|tel|url|number|file|radio|checkbox)"|<input|<select|<textarea/gi;
2485→  const totalFields = (ariaSnapshot.match(fieldPatterns) || []).length;
2486→
2487→  // Count required fields (marked with * or "required")
2488→  const requiredPattern = /\[required\]|aria-required="true"/gi;
2489→  const requiredFields = (ariaSnapshot.match(requiredPattern) || []).length;
2490→
2491→  // Check for resume upload
2492→  const hasResumeUpload = /resume|cv|curriculum/i.test(ariaSnapshot) && /type="file"|upload/i.test(ariaSnapshot);
2493→
2494→  // Check for multi-step wizard
2495→  const multiStepIndicators = /step \d+ of \d+|page \d+ of \d+/i;
2496→  const isMultiStep = multiStepIndicators.test(ariaSnapshot);
2497→
2498→  // Detect ATS type
2499→  let atsType = "generic";
2500→  if (/greenhouse/i.test(url)) atsType = "greenhouse";
2501→  else if (/lever/i.test(url)) atsType = "lever";
2502→  else if (/ashby/i.test(url)) atsType = "ashby";
2503→  else if (/workday/i.test(url)) atsType = "workday";
2504→  else if (/icims/i.test(url)) atsType = "icims";
2505→  else if (/jobvite/i.test(url)) atsType = "jobvite";
2506→
2507→  // Estimate difficulty
2508→  let estimatedDifficulty: "simple" | "moderate" | "complex" = "simple";
2509→  if (isMultiStep || requiredFields > 15) {
2510→    estimatedDifficulty = "complex";
2511→  } else if (requiredFields > 8 || totalFields > 12) {
2512→    estimatedDifficulty = "moderate";
2513→  }
2514→
2515→  return {
2516→    totalFields,
2517→    requiredFields,
2518→    hasResumeUpload,
2519→    isMultiStep,
2520→    estimatedDifficulty,
2521→    atsType,
2522→  };
